try {
const raw = $input.first().json;

const src = (raw.data !== undefined) ? raw
  : (raw.query?.data !== undefined) ? raw.query
  : (raw.body?.data !== undefined) ? raw.body
  : (raw.input?.data !== undefined) ? raw.input
  : raw;

return [{
  json: {
    data:       src.data       ?? null,
    categoria:  (src.categoria && String(src.categoria).trim() !== '') ? src.categoria : null,
    usuario_id: src.usuario_id ?? null
  }
}];
} catch (e) {
  return [{ json: { success: false, error_code: 'CODE_ERROR', message: '[FN - Normaliza Payload] ' + (e.message || 'Erro desconhecido') } }];
}

try {
const data = $input.first().json;
const erros = [];

if (!data.data || String(data.data).trim() === '') {
  erros.push('data é obrigatório (formato MM/YYYY)');
}
if (!data.usuario_id || String(data.usuario_id).trim() === '') {
  erros.push('usuario_id é obrigatório');
}

return [{
  json: {
    ...data,
    inputs_validos: erros.length === 0,
    erros_validacao: erros
  }
}];
} catch (e) {
  return [{ json: { success: false, error_code: 'CODE_ERROR', message: '[FN - Valida Inputs] ' + (e.message || 'Erro desconhecido') } }];
}

