try {
const data = $input.first().json;
const resumo = data.resumo_financeiro;
const r = typeof resumo === 'string' ? JSON.parse(resumo) : resumo;

if (!r || r.qtd_transacoes === 0 || r.qtd_transacoes === undefined) {
  return [{ json: { response: '📊 Não há registros no período solicitado.' } }];
}

function fmt(v) {
  return Number(v || 0).toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}

const periodo = r.periodo || data.data || '';
let msg = '*📊 Resumo Financeiro — ' + periodo + '*\n\n';
msg += '💰 *Entradas:* R$ ' + fmt(r.total_entradas) + '\n';
msg += '💸 *Saídas:* R$ ' + fmt(r.total_saidas) + '\n';

const saldo = Number(r.total_entradas || 0) - Number(r.total_saidas || 0);
msg += '📊 *Saldo:* R$ ' + fmt(saldo) + '\n';
msg += '📝 *Transações:* ' + r.qtd_transacoes + '\n';

const transacoes = r.transacoes || r.lista_transacoes || [];
if (transacoes.length > 0) {
  msg += '\n*Maiores movimentações:*\n';
  const sorted = [...transacoes].sort((a, b) => {
    const va = Math.abs(Number(a.saida || 0)) + Math.abs(Number(a.entrada || 0));
    const vb = Math.abs(Number(b.saida || 0)) + Math.abs(Number(b.entrada || 0));
    return vb - va;
  });
  const top = sorted.slice(0, 10);
  top.forEach((t, i) => {
    const valor = Number(t.saida || 0) > 0
      ? '💸 R$ ' + fmt(t.saida)
      : '💰 R$ ' + fmt(t.entrada);
    const cat = t.categoria ? ' (' + t.categoria + ')' : '';
    msg += (i + 1) + '. ' + (t.transacao || t.descricao || '?') + cat + ' — ' + valor + '\n';
  });
  if (transacoes.length > 10) {
    msg += '\n_...e mais ' + (transacoes.length - 10) + ' transações menores._';
  }
}

return [{ json: { response: msg } }];
} catch (e) {
  return [{ json: { response: '⚠️ Erro ao formatar resumo: ' + (e.message || 'Erro desconhecido') } }];
}

